window.__QUIZ_DATA__=[{"id":"theory>Geography>2021>1>a>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The table X below contains information of population of four districts of country Z in the year 2016, use the information to answer the question which follows  Table X  District population (millions) Land area(km2)A5.560000B8.0105000C6.7125000D4.888000    Calculate the population of country Z","images":[],"marking_scheme":"Total population of country Z = 5,500,000 + 8,000,000 + 6,700,000 + 4,800,000 = 25,000,000  total population of country Z = 25,000,000","marks":"6","difficulty":"2"},{"id":"theory>Geography>2021>1>a>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The table X below contains information of population of four districts of country Z in the year 2016, use the information to answer the question which follows  Table X  District population (millions) Land area(km2)A5.560000B8.0105000C6.7125000D4.888000    total land area of country Z","images":[],"marking_scheme":"total land area of country  z = 60,000 + 105,000 + 125,000 + 88,000 = 378,000 km2","marks":"4","difficulty":"2"},{"id":"theory>Geography>2021>1>a>iii","subject":"Geography","year":"2021","type":"Theory","sub_label":"iii","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The table X below contains information of population of four districts of country Z in the year 2016, use the information to answer the question which follows  Table X  District population (millions) Land area(km2)A5.560000B8.0105000C6.7125000D4.888000    population density of country Z","images":[],"marking_scheme":"populationdensityofacountryz=total populationtotal land area  =250,000378,000  therefore population  density of country Z = 66 persons per kilometer square.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2021>1>b","subject":"Geography","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"State four factor which are responsible for high population density","images":[],"marking_scheme":"Factor responsible for high population density of countries   - increase in birth rate   - presence of social amenities   - employment opportunities  - industrialization","marks":"3","difficulty":"1"},{"id":"theory>Geography>2021>1>c","subject":"Geography","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain three advantage associated with countries of high population density","images":[],"marking_scheme":"Advantage associated with countries of high population density  - information   - Effective planning   - large market  -large labour  - information  : there will be quick dissemination of information in the areas where there is high population density either through people, internet or mass media  - Effective planning  : large population brings concentration of effective planning so that town , city, can function properly.  - large market : high population is a source of large market for industries  - large labour : high population density provides large labour for industries","marks":"3","difficulty":"1"},{"id":"theory>Geography>2021>2>a>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Define settlement","images":[],"marking_scheme":"A settlement is a place where people live but it also include the people who lives there, the building , the road , street and pathways which link up building in the settlement and through which the people communicate .","marks":"6","difficulty":"1"},{"id":"theory>Geography>2021>2>a>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Name two types of urban settlement classified according to population size","images":[],"marking_scheme":"types of urban settlement classified according to population size  - Conurbation: it consists of several towns joined together but each town still maintains its identity. e.g Accra - Tema, Lagos - ikeja, Serondi-Takoradi  - Megalopolis : It is the largest form of urban settlement where neighbouring cities emerge and form one large city , E.g Washington, chicago","marks":"4","difficulty":"2"},{"id":"theory>Geography>2021>2>b","subject":"Geography","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"In what five ways are urban settlement dependent  on rural settlement","images":[],"marking_scheme":"ways are urban settlement dependent  on rural settlement  - provision of industrial raw materials for production of fruit drinks e.g pineapple to produce fruit drinks  - provision of foodstuffs e.g rice, yam, cassava, e.t.c  - provision of raw material for construction in urban settlement  - supply of unskilled labour :most youth migrate from the village to the cities and work as head porter in the town   - provision of market production and manufacturing of goods e.g textile e.t.c  - provision of medicinal herbs","marks":"6","difficulty":"3"},{"id":"theory>Geography>2021>2>c","subject":"Geography","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"outline three function of urban settlement","images":[],"marking_scheme":"- Residential function : The large number of urban settlement promotes the need for residential houses to accomodate majority of people to check to creation of slums and shanty settlements.  - Commercials functions : The presence of market, banks, hotel , insurance e.t.c in urban settlement enable urban dweller to engage in commercial activities such as trading, manufacturing e.t.c  - Social - cultural function : urban are places for the establishment of social and cultural infrastructures such as universities , churches , hotel , mosques , museums","marks":"4","difficulty":"2"},{"id":"theory>Geography>2021>3>a","subject":"Geography","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"What is tourism","images":[],"marking_scheme":"Tourism is the practice of travelling for pleasure or the business of offering information, accommodation , transportation and other services to tourists. in other words , tourism is the practice which involves the visiting of people to practice which involves the visiting of the people to place of interest where they can relax , derive pleasure and entertainment","marks":"7","difficulty":"1"},{"id":"theory>Geography>2021>3>b","subject":"Geography","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Outline five factors that favours the development of tourism","images":[],"marking_scheme":"- Effective publicity : for tourism to strive in Nigeria, There must be enough publicity to create awareness for the tourist on possible areas of attraction.    - Beautiful scenery : for tourism to grow there must be natural and man made scenery where people can relax and entertain themselves.  - Fine beaches : In nigeria, there exist beautiful beaches along the coast . Such beautiful beaches include the bar beaches, lekki, and Badagry  - Favourable climate : for tourism to strive, the climate of the environment must be favourable so that tourist can re;ax and enjoy themselves.","marks":"7","difficulty":"2"},{"id":"theory>Geography>2021>3>c","subject":"Geography","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TOURISM","question":"Highlight four problems created by tourism industry in developing countries","images":[],"marking_scheme":"created by tourism industry in developing countries  - inadequate funding : in Nigeria, there is a poor funding of tourism industry, poor funding has led to the poor development of te sub-sector   - Lack of accessable roads : In nigeria there is basically lack of accessable road to most resort centers. Many of the roads are in bad shape and this tends not to attracts tourist to such centers  - poor publicity : lack of attractive publicity or communication system for publicizing the scenery, wildlife and cultural attractions to visitors is a big problem in the country  - Inadequate personnel : one ot the problems of developing tourism attraction in Nigeria is the inadequacy of competent and trained tourism personnel. Very few personnel are trained and competent.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2021>4>a>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of nigeria    The kanji dam","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"7","difficulty":"3"},{"id":"theory>Geography>2021>4>a>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of nigeria   Lake chad","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Geography>2021>4>a>iii","subject":"Geography","year":"2021","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw a sketch map of nigeria   Ibadan","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Geography>2021>4>b","subject":"Geography","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Highlight three factor that impede the development of solar energy in Nigeria","images":[],"marking_scheme":"factor that impede the development of solar energy in Nigeria   - availability of loans at a high interest rate   - poor business development skills by solar energy system vendors  - un-supportive climate for investments   - lack of access to micro financing","marks":"3","difficulty":"2"},{"id":"theory>Geography>2021>4>c","subject":"Geography","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Explain four problems created by construction of kanji dam in Nigeria","images":[],"marking_scheme":"problems created by construction of kanji dam in Nigeria  - Declination in the fishing industry : The decline in the fishing industry at the coast due to cost of silt deposite now setting out in the lake , which would support plankton growth.  - Reduction in the size of the delta : The delta has reduced in size as it is not recieving significant deposits and hence currents are eroding of the delta and the limits costal delta activites such as tourism.  - Displacement of people by the formation of the konji dam reservoir. Many villages were submerged and over 60,000 people were displaced, hence costly resettlement   - loss of grazing land : the loss of grazing land occurred since a large area formerly occupied by nomads was drowned by lake konji  - Existence of stagnant water an their can lead to the spreading of water borne disease.","marks":"3","difficulty":"3"},{"id":"theory>Geography>2021>5>a>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw a sketch map of nigeria, on the map, show and name    Latitude 4oN and 14oN","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"1"},{"id":"theory>Geography>2021>5>a>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw a sketch map of nigeria, on the map, show and name   Longitude 3oE ad 15oE","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"1"},{"id":"theory>Geography>2021>5>a>iii","subject":"Geography","year":"2021","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw a sketch map of nigeria, on the map, show and name   Enugu","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"1"},{"id":"theory>Geography>2021>5>b>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe Nigeria under the following headings    Size","images":[],"marking_scheme":"Size  :  Nigeria land mass is approximately 923,788 square kilometers. the greatest distance from East to West is approximately 1300 km while from North to south is about 1100km. it us about 200 millions in population","marks":"4","difficulty":"1"},{"id":"theory>Geography>2021>5>b>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe Nigeria under the following headings   location","images":[],"marking_scheme":"Nigeria is located between 4oN and 14oN of the equator and 3oE of the green meridian . The latitudinal stretch is about 10o while longitudinal stretch is about 12o","marks":"6","difficulty":"1"},{"id":"theory>Geography>2021>5>b>iii","subject":"Geography","year":"2021","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Describe Nigeria under the following headings   position","images":[],"marking_scheme":"Nigeria is in west africa , she is bound in the west by Benin republic in the north by Niger republic, In the east by Cameroon and chad republic and in the south by the gulf of guinea","marks":"4","difficulty":"1"},{"id":"theory>Geography>2021>6>a>i","subject":"Geography","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"List four industrial towns in Nigeria","images":[],"marking_scheme":"- Lagos state   - Rivers state  -Ogun state  -Anambra","marks":"8","difficulty":"2"},{"id":"theory>Geography>2021>6>a>ii","subject":"Geography","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Indicate one type of industrial activity in each of the town listed in 6ai","images":[],"marking_scheme":"- Lagos state : Manufacturing and innovation industries e.t.c  - Rivers state : oil and gas industries  - Ogun State : manufacturing industries like Gee-pee tank, Apex paints limited, Drury industries limited , e.t.c  - Anambra state : mineral resources industries","marks":"4","difficulty":"2"},{"id":"theory>Geography>2021>6>b","subject":"Geography","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"outline three contribution of industries to economic development of Nigeria","images":[],"marking_scheme":"contribution of indutries to economic develpment of Nigeria   - Employment opportunities : Industries provides employment (jobs) for many people  - increase in Gross National product (GNP) : industrial sector through their operation like, payment of taxes increase the earnings accruing to the nations   - international trade improves trade balance : most of the products of manufacturing industries like machinery are usually from western counties or nations, this forms the basis for international trade and this improves trade balance between countries .","marks":"3","difficulty":"1"},{"id":"theory>Geography>2021>6>c","subject":"Geography","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Identify three problems which are limiting industrial development in Nigeria","images":[],"marking_scheme":"- Storage of raw materials : lack sufficient raw materials available industries hinders large scale production   - Insufficient capital : Access to finance or loan is very difficult , Capital (i.e loan) is only easy for the big time investors, who posses collateral securities to secure .  - High degree for foreign dependence : most products made i Africa are of low quality when compared with their counterparts in developed countries , Hence , people rely or depend on foreign  goods.","marks":"3","difficulty":"2"}];